import { ref } from 'vue'
import { submitFlow as apiSubmitFlow, getFlow as apiGetFlow, getSubmitterFlows as apiGetSubmitterFlows } from '@/api/flows'
import { useNotificationsStore } from '@/stores/notifications'
import type { FlowStatus, FlowStatusWithHistory, SubmitDocumentRequest } from '@/api/models'

export function useFlows() {
  const currentFlow = ref<FlowStatusWithHistory | null>(null)
  const submittedFlows = ref<FlowStatus[]>([])
  const isLoading = ref(false)
  const error = ref<string | null>(null)

  async function submitFlow(payload: SubmitDocumentRequest): Promise<FlowStatus> {
    isLoading.value = true
    error.value = null
    try {
      const result = await apiSubmitFlow(payload)
      currentFlow.value = result as FlowStatusWithHistory
      return result
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Submission failed'
      throw e
    } finally {
      isLoading.value = false
    }
  }

  async function fetchFlow(flowId: string): Promise<void> {
    isLoading.value = true
    error.value = null
    try {
      currentFlow.value = await apiGetFlow(flowId)
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Failed to load flow'
      throw e
    } finally {
      isLoading.value = false
    }
  }

  async function fetchSubmittedFlows(): Promise<void> {
    isLoading.value = true
    error.value = null
    try {
      submittedFlows.value = await apiGetSubmitterFlows()
      const notifications = useNotificationsStore()
      notifications.updateFromFlows(submittedFlows.value)
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Failed to load flows'
      throw e
    } finally {
      isLoading.value = false
    }
  }

  return { currentFlow, submittedFlows, isLoading, error, submitFlow, fetchFlow, fetchSubmittedFlows }
}

import { createRouter, createWebHistory, type RouteLocationNormalized } from 'vue-router'
import { useAuthStore } from '@/stores/auth'
import { getGroupWorklist } from '@/api/worklist'
import { handleCallback, silentRenew, getUser } from '@/auth/oidc'

const router = createRouter({
  history: createWebHistory(),
  routes: [
    {
      path: '/auth/callback',
      name: 'auth-callback',
      component: () => import('@/views/AuthCallbackView.vue'),
      meta: { public: true },
    },
    {
      path: '/auth/silent-renew',
      name: 'auth-silent-renew',
      component: () => import('@/views/AuthSilentRenewView.vue'),
      meta: { public: true },
    },
    {
      path: '/submissions',
      name: 'my-submissions',
      component: () => import('@/views/MySubmissionsView.vue'),
    },
    {
      path: '/submit/:definitionId',
      name: 'submit-flow',
      component: () => import('@/views/SubmitFlowView.vue'),
    },
    {
      path: '/flows/:flowId',
      name: 'flow-detail',
      component: () => import('@/views/FlowDetailView.vue'),
    },
    {
      path: '/worklist',
      name: 'worklist',
      component: () => import('@/views/WorklistView.vue'),
    },
    {
      path: '/tasks/:taskId',
      name: 'task-detail',
      component: () => import('@/views/TaskDetailView.vue'),
    },
    {
      path: '/',
      redirect: () => ({ name: 'my-submissions' }),
    },
  ],
})

router.beforeEach(async (to: RouteLocationNormalized) => {
  if (to.meta.public) return true

  const auth = useAuthStore()
  await auth.loadUser()

  if (!auth.isAuthenticated) {
    await auth.signIn(to.fullPath)
    return false
  }

  // Smart landing: redirect to worklist if user has pending tasks (FR-016)
  if (to.path === '/' || to.name === 'my-submissions') {
    try {
      const tasks = await getGroupWorklist()
      if (tasks.length > 0) {
        return { name: 'worklist' }
      }
    } catch {
      // If worklist call fails, proceed to submissions as default
    }
  }

  return true
})

export { router }
export default router

