import { describe, it, expect, beforeEach } from 'vitest'
import { setActivePinia, createPinia } from 'pinia'
import { useNotificationsStore } from '@/stores/notifications'

describe('useNotificationsStore', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    sessionStorage.clear()
  })

  it('reworkPendingCount increments when a RETURNED_FOR_REWORK flow is present', () => {
    const store = useNotificationsStore()
    store.updateFromFlows([
      { flowId: 'f1', currentState: 'RETURNED_FOR_REWORK' } as never,
      { flowId: 'f2', currentState: 'PENDING_REVIEW' } as never,
    ])
    expect(store.reworkPendingCount).toBe(1)
  })

  it('reworkPendingCount excludes flows already marked seen', () => {
    const store = useNotificationsStore()
    store.updateFromFlows([
      { flowId: 'f1', currentState: 'RETURNED_FOR_REWORK' } as never,
      { flowId: 'f2', currentState: 'RETURNED_FOR_REWORK' } as never,
    ])
    expect(store.reworkPendingCount).toBe(2)

    store.markSeen('f1')
    expect(store.reworkPendingCount).toBe(1)
  })

  it('reworkPendingCount is 0 when no rework flows present', () => {
    const store = useNotificationsStore()
    store.updateFromFlows([
      { flowId: 'f1', currentState: 'APPROVED' } as never,
    ])
    expect(store.reworkPendingCount).toBe(0)
  })
})

import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import type { FlowSummary } from '@/api/models'

export const useNotificationsStore = defineStore('notifications', () => {
  const seenReworkFlowIds = ref<Set<string>>(
    new Set(JSON.parse(sessionStorage.getItem('seenReworkIds') ?? '[]') as string[]),
  )

  const reworkFlows = ref<FlowSummary[]>([])

  const reworkPendingCount = computed(
    () =>
      reworkFlows.value.filter(
        (f) =>
          f.currentState === 'RETURNED_FOR_REWORK' &&
          !seenReworkFlowIds.value.has(f.flowId ?? ''),
      ).length,
  )

  function updateFromFlows(flows: FlowSummary[]): void {
    reworkFlows.value = flows
  }

  function markSeen(flowId: string): void {
    seenReworkFlowIds.value.add(flowId)
    sessionStorage.setItem('seenReworkIds', JSON.stringify([...seenReworkFlowIds.value]))
  }

  return { reworkPendingCount, reworkFlows, updateFromFlows, markSeen }
})

import { ref } from 'vue'
import { submitFlow as apiSubmitFlow, getFlow as apiGetFlow, getSubmitterFlows as apiGetSubmitterFlows } from '@/api/flows'
import { useNotificationsStore } from '@/stores/notifications'
import type { FlowStatus, FlowStatusWithHistory, FlowSummary, FlowSubmitRequest } from '@/api/models'

export function useFlows() {
  const currentFlow = ref<FlowStatusWithHistory | null>(null)
  const submittedFlows = ref<FlowSummary[]>([])
  const isLoading = ref(false)
  const error = ref<string | null>(null)

  async function submitFlow(payload: FlowSubmitRequest): Promise<FlowStatus> {
    isLoading.value = true
    error.value = null
    try {
      const result = await apiSubmitFlow(payload)
      currentFlow.value = result as FlowStatusWithHistory
      return result
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Submission failed'
      throw e
    } finally {
      isLoading.value = false
    }
  }

  async function fetchFlow(flowId: string): Promise<void> {
    isLoading.value = true
    error.value = null
    try {
      currentFlow.value = await apiGetFlow(flowId)
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Failed to load flow'
      throw e
    } finally {
      isLoading.value = false
    }
  }

  async function fetchSubmittedFlows(): Promise<void> {
    isLoading.value = true
    error.value = null
    try {
      submittedFlows.value = await apiGetSubmitterFlows()
      const notifications = useNotificationsStore()
      notifications.updateFromFlows(submittedFlows.value)
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Failed to load flows'
      throw e
    } finally {
      isLoading.value = false
    }
  }

  return { currentFlow, submittedFlows, isLoading, error, submitFlow, fetchFlow, fetchSubmittedFlows }
}

import { api } from './client'
import type { FlowStatus, FlowStatusWithHistory, FlowSummary, FlowSubmitRequest } from './models'

export async function submitFlow(payload: FlowSubmitRequest): Promise<FlowStatus> {
  return api.post<FlowStatus>('/flows', {
    definitionKey: payload.definitionId,
    documentRef: JSON.stringify(payload.formData),
  })
}

export async function getFlow(flowId: string): Promise<FlowStatusWithHistory> {
  return api.get<FlowStatusWithHistory>(`/flows/${flowId}`)
}

export async function getSubmitterFlows(): Promise<FlowSummary[]> {
  return api.get<FlowSummary[]>('/flows')
}

// Clean re-exports of generated OpenAPI schema types.
// Import from this file; never import directly from types.ts.
import type { components } from './types'

export type FlowStatus = components['schemas']['FlowStatus']
export type FlowStatusWithHistory = components['schemas']['FlowStatusWithHistory']
export type FlowSummary = components['schemas']['FlowSummary']
export type TaskSummary = components['schemas']['TaskSummary']
export type SubmitDocumentRequest = components['schemas']['SubmitDocumentRequest']
export type DecisionRequest = components['schemas']['DecisionRequest']

// Frontend-facing submit payload — form data is encoded as documentRef JSON.
// api/flows.ts translates this to the backend SubmitDocumentRequest.
export interface FlowSubmitRequest {
  definitionId: string
  formData: Record<string, string>
}

// Frontend extended task — backend returns stateName/candidateGroupId/ownerId;
// aliased here to match how the views reference them.
export interface RichTaskSummary extends TaskSummary {
  definitionStage: string
  candidateGroupId: string
  ownerId?: string | null
}

// Frontend extended flow — backend returns currentState + documentRef;
// formData is decoded from documentRef if it was submitted as JSON.
export interface RichFlowStatus extends FlowStatus {
  currentState: string
  formData?: Record<string, unknown>
  history?: components['schemas']['AuditEntry'][]
}

export type FlowState =
  | 'PENDING_REVIEW'
  | 'APPROVED'
  | 'REJECTED'
  | 'RETURNED_FOR_REWORK'
  | 'COMPLETED'

export type TaskState = 'PENDING' | 'CLAIMED' | 'COMPLETED'

export interface FieldDefinition {
  name: string
  label: string
  type: 'text' | 'textarea' | 'select' | 'date'
  required: boolean
  options?: string[]
}

export interface WorkflowDefinition {
  definitionId: string
  name: string
  initiatorGroup: string
  fields: FieldDefinition[]
}

